// Script Continued Below
var TaskerHelpers = Class.create();
TaskerHelpers.prototype = {
	initialize: function() {
		this.tableRouteTaskInstance = 'x_153465_discovert_route_task_instance';
	},

	getDefaultReviewerDisplayValue: function(gr_task){
		return this.getReviewer(gr_task, "", true);	
	},

	// STRY0156233 
	getReviewer: function(gr_task, reviewer, getDisplayValue){
		var retVal;
		var reviewerDisplayValue = gr_task.getDisplayValue("u_reviewer");
		if(gr_task.tasker_type.work_type != "review_item") { //Standard Task Type
			if(!(gr_task.reviewer_manual_update) || reviewer == "") {
				if(gr_task.isNewRecord() || reviewer == "") {
					if(gr_task.parent && gr_task.parent.assigned_to) {
						// set reviewer to parent assigned
						reviewer = gr_task.parent.assigned_to;
						reviewerDisplayValue = gr_task.parent.assigned_to.getDisplayValue();
						// if the assigned is not valid
					} else if(gr_task.parent) {
						// set the task owner
						reviewer = gr_task.parent.u_task_requester;
						reviewerDisplayValue = gr_task.parent.u_task_requester.getDisplayValue();
					}
				}
				if(reviewer ==""){
					// parent is invalid - top task
					if(!gr_task.parent && gr_task.originator){
						// set originator
						reviewer = gr_task.originator;
						reviewerDisplayValue = gr_task.getDisplayValue("originator");

					}
				}
			}
		}
		if(getDisplayValue){
			retVal = reviewerDisplayValue;
		} else {
			retVal = reviewer;
		}

		return retVal;
	},

	// STRY0140267 
	getParentPrimaryOfficeTaskAdministrators: function(grObj){
		var GTAs = "";
		var grTask = new GlideRecord("x_153465_discovert_route_task_instance");
		if(grTask.get(grObj.parent)){
			GTAs = this.getPrimaryOfficeTaskAdministrators(grTask);

		}
		return GTAs;
	},

	// STRY0140267 
	getPrimaryOfficeTaskAdministrators: function(grTask){
		var GTAs = "";
		// STRY0140267 - get the Task Administrators from the Top OU of the Primary Assignee
		var primary_office = grTask.getValue("primary_office");
		var grPrimaryOffice = new GlideRecord("x_153465_discovert_discover_office_hierarchy");
		if(grPrimaryOffice.get(primary_office)){
			GTAs = grPrimaryOffice.u_top_ou.u_global_authorities.toString();
		}
		return GTAs;		
	},

	// STRY0140267 
	getPrimaryAssigneeTaskAdministrators: function(grTask){
		var GTAs = "";
		// STRY0140267 - get the Task Administrators from the Top OU of the Primary Assignee
		var primary_assignee = grTask.getValue("primary_assignee");
		var grPrimaryAssignee = new GlideRecord("x_153465_discovert_discover_office_hierarchy");
		if(grPrimaryAssignee.get(primary_assignee)){
			GTAs = grPrimaryAssignee.u_top_ou.u_global_authorities.toString();
		}
		return GTAs;		
	},

	// STRY0130088
	getSubCategoryCount: function(category_id){
		var subCategoryCount = 0;
		var gaSubCat = new GlideAggregate('x_153465_discovert_discover_tasker_subcategory');
		gaSubCat.addQuery('category',category_id);
		gaSubCat.addAggregate('COUNT');
		gaSubCat.query();
		if(gaSubCat.next()){
			subCategoryCount = gaSubCat.getAggregate('COUNT');			
		}
		return subCategoryCount;
	},	

	getActiveApprovalDependantsCount: function (task_id){
		return this._getApprovalDependantsCount(task_id, true);
	},

	getDraftApprovalDependantsCount: function (task_id){
		return this._getApprovalDependantsCount(task_id, false);
	},

	// STRY0111263 - count the dependent tasks for this review task type
	_getApprovalDependantsCount: function(task_id, active){
		// DFCT0011046 - added to make eaiser to debug
		var descendantCount = 0;
		var descendantApprovalCount = 0;
		var grTask = new GlideRecord(this.tableRouteTaskInstance);
		var parentId;
		var topTaskId;
		var isParentReviewType = false;
		var taskDescendants = 0;
		var dependentTasks = 0;
		var details = {
			taskSysId: task_id,
			countType: 'EXCLUDE_CLOSE'
		};

		if(grTask.get(task_id)){
			// if the task has a parent
			parentId = grTask.getValue("parent");
			if(parentId){
				var grParent = new GlideRecord(this.tableRouteTaskInstance);
				while(grParent.get(parentId) && grParent.work_item_type == "review_item"){
					topTaskId = grParent.getUniqueValue(); 
					parentId = grParent.getValue("parent");
				}
			}

			// if a top task was set, then an ancestor task of this task was a review type, so all tasks under that will close, so count everything below it
			// STRY0125927
			if(topTaskId) {
				details.taskSysId = topTaskId;
				if(active){
					// DFCT0011046 - added to make eaiser to debug
					descendantCount = parseInt(this.getDescendantsCount(details));
					taskDescendants = descendantCount + 1; // add one to account for the top task
				}else {
					// STRY0125927
					taskDescendants = parseInt(this.getDraftDescendantsCount(details.taskSysId));
				}

			} else {
				if(active){
					// DFCT0011046 - added to make eaiser to debug
					descendantCount = parseInt(this.getDescendantsCount(details));
					taskDescendants = descendantCount;
					// count other dependent tasks based on review type rules
					// rule: find the next non-review type under this parent, 
					// count all of the tasks that will close until we find a non-reviewtype that is active
				}else {
					// STRY0125927
					taskDescendants = parseInt(this.getDraftDescendantsCount(details.taskSysId));
				}

			}

			// if the parentId has a value, then the task represented by the parentId is not a review type
			// so, check the children of this task to see if there are active tasks in a task order that are not review type
			if(parentId){
				// DFCT0011046 - added to make eaiser to debug
				// STRY0125927 - added active to the end
				// DFCT0011135  - count issue.  active was not being passed in as it was in parseInt function, not the count function call
				descendantApprovalCount = parseInt(this._countDependentApprovalTasks(parentId, grTask.getValue("task_order"), active));
				// the current task being rejected is an active review task in the current order.  So, subtract 1 from the total
				descendantApprovalCount = descendantApprovalCount - 1;
				dependentTasks = descendantApprovalCount;
			}
		}
		return taskDescendants + dependentTasks;
	},

	// STRY0111263 - count the dependent tasks for this review task type
	// STRY0125927 - added active to the end
	_countDependentApprovalTasks: function(parentId, taskOrder, active){
		// DFCT0011046 - added to make eaiser to debug
		var descendantApprovalCount = 0;
		var countActiveInOrder = 0;
		// this is the count of tasks that are dependent on this rejection and will close if this task is rejected
		var countActiveReviewInOrder = 0;  
		var countActiveInLaterOrder = 0;
		taskOrder = parseInt(taskOrder);
		var nextOrder = taskOrder + 1;

		var gaDraftInOrder = new GlideAggregate('x_153465_discovert_route_task_instance');
		var gaActiveReviewTypeInOrder = new GlideAggregate('x_153465_discovert_route_task_instance');
		var gaActiveInOrder = new GlideAggregate('x_153465_discovert_route_task_instance');
		var gaActiveInLaterOrder = new GlideAggregate('x_153465_discovert_route_task_instance');

		// count non-approval tasks (approvals were all clsed, so just count acitve), in the current order
		gaActiveReviewTypeInOrder.addQuery("parent", parentId);
		gaActiveReviewTypeInOrder.addQuery("task_order", taskOrder);
		gaActiveReviewTypeInOrder.addQuery("work_item_type","review_item");
		gaActiveReviewTypeInOrder.addQuery("active", true);
		gaActiveReviewTypeInOrder.addAggregate('COUNT');
        gaActiveReviewTypeInOrder.query();
        if (gaActiveReviewTypeInOrder.next()){
			countActiveReviewInOrder = parseInt(gaActiveReviewTypeInOrder.getAggregate('COUNT'));
		}

		// STRY0125927 - get count of draft in this order
		var draftCountInOrder = 0;
		if(!active){
			gaDraftInOrder.addQuery("parent", parentId);
			gaDraftInOrder.addQuery("task_order", taskOrder);
			gaDraftInOrder.addQuery("active", true);
			// STRY0125927 - don't count a draft task as active
			gaDraftInOrder.addQuery("state", -6);
			gaDraftInOrder.addAggregate('COUNT');
			gaDraftInOrder.query();
			if (gaDraftInOrder.next()){
				draftCountInOrder = gaDraftInOrder.getAggregate('COUNT');
			}
		}

		// count non-approval tasks in the current order, if one is found, stop the recursion
		gaActiveInOrder.addQuery("parent", parentId);
		gaActiveInOrder.addQuery("task_order", taskOrder);
		gaActiveInOrder.addQuery("work_item_type", "!=", "review_item");
		gaActiveInOrder.addQuery("active", true);
		// STRY0125927 - don't count a draft task as active
		gaActiveReviewTypeInOrder.addQuery("state", "!=", -6);
		gaActiveInOrder.addAggregate('COUNT');
        gaActiveInOrder.query();
        if (gaActiveInOrder.next()){
			countActiveInOrder = gaActiveInOrder.getAggregate('COUNT');
		}
		// return the count of items that are dependent
		if(countActiveInOrder > 0){
			// STRY0125927
			if(active){
				return countActiveReviewInOrder;
			} else {
				return draftCountInOrder;
			}
		} else {
			// if no active task that are not review type in current order, move to next order
			gaActiveInLaterOrder.addQuery("parent", parentId);
			gaActiveInLaterOrder.addQuery("task_order",">", taskOrder);
			gaActiveInLaterOrder.addQuery("active", true);
			gaActiveInLaterOrder.addAggregate('COUNT');
			gaActiveInLaterOrder.query();
			if (gaActiveInLaterOrder.next()){
				countActiveInLaterOrder = gaActiveInLaterOrder.getAggregate('COUNT');
			}
			// if there are active tasks in the next order, but not in this order, look for a non review
			// type in the next order
			if(countActiveInLaterOrder>0){
				// DFCT0011046 - added to make eaiser to debug
				descendantApprovalCount = parseInt(this._countDependentApprovalTasks(parentId, nextOrder, active));
				// STRY0125927
				if(active){
					// recurse this function to move to the next task order
					return countActiveReviewInOrder + descendantApprovalCount;
				} else {
					return draftCountInOrder + descendantApprovalCount;
				}
			} else {
				// DFCT0011046 - no active tasks in orders after this, return the active reviews in this order
				return countActiveReviewInOrder;
			}
		}
	},	

	// STRY0116802
	// The method below updates the Tasker Number OUs
	// This method is currently implemented as an fix script and is not run when an abbreviation is changed
	// The function receives active only and runs for either all tasks or for all active only tasks
	// Iterate all Active Tasks or All tasks in the OU given
	// Update the Tasker Number for all tasks (or all active tasks) to match the new OU Abbreviation
	// Result: Tasks (or all Active Tasks) in the OU will have Tasker Number ending with the new OU Abbreviation.
	updateTaskerNumber: function(ou_id, activeOnly){
		var gr_ou = new GlideRecord('x_153465_discovert_discover_office_hierarchy');
		var gr_ouTasks = new GlideRecord('x_153465_discovert_route_task_instance');
		var taskerNumber;
		var msgOUNotFound = gs.getMessage('Tasker - The Organizational Unit provided was not found. The Organizaitonal Unit sys_id provided was:') + ou_id;
		var msgAllTasks="";
		var msgActiveTasks="";
		var msgEnd = "";

		var countTasksToUpdate = 0;
		var countTasksUpdated = 0;
		var updateProcessingObject = {sys_id: ou_id, ou_abbreviation:"", office_name: "", tasksToUpdate: 0, tasksUpdated: 0};
		// only process tasks if the OU is found
		if(gr_ou.get(ou_id)){
			countTasksToUpdate = this.countTasksInOU(ou_id, activeOnly);

			// set up the glide record to process the tasks
			gr_ouTasks.addQuery("primary_assignee",ou_id);

			// add active only to the query and update the message
			if(activeOnly){
				gr_ouTasks.addQuery("active",true);
			}
			// put message to the screen givign the count
			if(activeOnly){
				msgActiveTasks = gs.getMessage('Tasker - Tasker is updating the Tasker Number for all active tasks for the Organizational Unit with Abbreviation [{0}]. Tasks being updated [{1}]',[gr_ou.getDisplayValue(), countTasksToUpdate]);
				gs.info(msgActiveTasks);
			} else{
				msgAllTasks =gs.getMessage('Tasker - Tasker is updating the Tasker Number for all tasks for the Organizational Unit with Abbreviation [{0}]. Tasks being updated [{1}].',[gr_ou.getDisplayValue(), countTasksToUpdate]);
				gs.info(msgAllTasks);
			}
			gr_ouTasks.query();
			while(gr_ouTasks.next()){
				taskerNumber = gr_ouTasks.u_task_tree.u_shared_task_label + '-' + gr_ouTasks.getDisplayValue('primary_assignee');
				if(gr_ouTasks.taskernumber != taskerNumber){
					countTasksUpdated++;
					gr_ouTasks.taskernumber = taskerNumber;
					gr_ouTasks.update();
				}
			}
			msgEnd = gs.getMessage('Tasker - The number of Tasker Numbers updated in the Organizational Unit with Abbreviation [{0}]. was [{1}]',[gr_ou.getDisplayValue(), countTasksUpdated]);
			gs.info(msgEnd);

			updateProcessingObject.sys_id = ou_id;
			updateProcessingObject.ou_abbreviation = gr_ou.getDisplayValue("office_abbreviation");
			updateProcessingObject.office_name = gr_ou.getDisplayValue("office_name");
			updateProcessingObject.tasksToUpdate = countTasksToUpdate;
			updateProcessingObject.tasksUpdated = countTasksUpdated;
		} else {
			gs.info(msgOUNotFound);
		}
		return updateProcessingObject;
	},
	// STRY0116785 
	countTasksInOU: function (ou_id, activeOnly){
		var countTasksToUpdate = 0;
		// set up the glide aggregate
		var ga_ouTasks = new GlideAggregate('x_153465_discovert_route_task_instance');
		ga_ouTasks.addQuery("primary_assignee",ou_id);
		// add active only to the query and update the message
		if(activeOnly){
			ga_ouTasks.addQuery("active",true);
		}
		// count the records being updated
		ga_ouTasks.addAggregate('COUNT');
		ga_ouTasks.query();
		if (ga_ouTasks.next()) {
			// Need to subtract 1 since this task is also in the list of ancestors
			countTasksToUpdate = ga_ouTasks.getAggregate('COUNT');
		}
		return countTasksToUpdate;

	},

	// STRY0122882 
	getDraftDescendantsCount: function (taskSysId) {
		var countDescendants = '0';
        var filter_ancestors = 'u_all_ancestors_tasksLIKE' + taskSysId;
        var gaSubTasks = new GlideAggregate(this.tableRouteTaskInstance);

        gaSubTasks.addEncodedQuery(filter_ancestors);
		gaSubTasks.addQuery('sys_id', '!=', taskSysId);
		gaSubTasks.addQuery('state', '-6'); // -6 = Draft
        gaSubTasks.addAggregate('COUNT');
        gaSubTasks.query();

        if (gaSubTasks.next()) {
            // Need to subtract 1 since this task is also in the list of ancestors
            countDescendants = gaSubTasks.getAggregate('COUNT');
        }

		// returns a string
		return countDescendants;
    },
	// 2.7.0 | 2021-10-8 | mmcc | STRY0109110 - Draft Scheduled Tasks – UI – Delete Modal- Add Descendant tasks count
	getDescendantsCount: function (params) {

        var countDescendants = '0';
        var filter_ancestors = 'u_all_ancestors_tasksLIKE' + params.taskSysId;
        var gaSubTasks = new GlideAggregate(this.tableRouteTaskInstance);

        gaSubTasks.addEncodedQuery(filter_ancestors);
		gaSubTasks.addQuery('sys_id', '!=', params.taskSysId);

		// 2.7.0 | 2021-10-18 | mmcc |  STRY0108860 - DIA- Completed from Top Task Notification
		if (params.countType == 'EXCLUDE_CLOSE') {
			gaSubTasks.addQuery('state', 'NOT IN', '3, 4, 7'); // 3 = Completed; 4 = Closed Incomplete; 7 = Cancelled
		}

		// 2.8 | 2022-04-12 | mmcc | STRY0113587 - Mass Reopen Task Modal- Update Labels for UX; check for undefined && empty then add to the query
		if (!!params.taskClosedDate && params.taskClosedDate !== '') {
			gaSubTasks.addQuery('closed_at', '>=', new GlideDateTime(params.taskClosedDate));
		}

        gaSubTasks.addAggregate('COUNT');
        gaSubTasks.query();

        if (gaSubTasks.next()) {
            // Need to subtract 1 since this task is also in the list of ancestors
            countDescendants = gaSubTasks.getAggregate('COUNT');
        }

		// returns a string
		return countDescendants;
    },

	// STRY0122882 
	getTaskToPublish: function(gr_task){
		var taskToPublish = "";
		var userCanPublish = new uiConditionCheck().canPublishDraftTask(gr_task);
		if(!userCanPublish){
			// find the task that can be published and provide link to page
			taskToPublish = this._getDraftAncestor(gr_task);
			// we know this task can't be pubhlished and we didn't find an ancestor in draft state at the top
			// so, it cannot be publshed b/c of a previous task order, find a task in the earliest task order
			if(!taskToPublish ||
				taskToPublish == "" ||
				taskToPublish == gr_task.getUniqueValue()){
				taskToPublish = this._getDraftInPreviousTaskOrder(gr_task.parent, gr_task.task_order);
			}
		}		
		return taskToPublish;
	},

	// STRY0122882 - is the parent in a draft state
	_getDraftAncestor: function(gr_task){
		var ancestor_id;
		// came into this function b/c the task is in draft state
		// if no parent, then return this task as it is the top task
		if(!gr_task.parent){
			// return this task, it is the top draft task
			ancestor_id = gr_task.getUniqueValue();
		} else {
			// go up to the parent
			var grParentTask = new GlideRecord('x_153465_discovert_route_task_instance');
			if(grParentTask.get(gr_task.parent)){
				if(grParentTask.state == -6){
					// parent is in draft state, call this function again to go up to the parent
					ancestor_id = this._getDraftAncestor(grParentTask);
				} else {
					// parent task is not in draft, so this task is the highest draft task as we came into this function b/c this task is in draft
					ancestor_id = gr_task.getUniqueValue();
				}
			}
		}
		return ancestor_id;
	},

	// STRY0122882 - gets a the draft task in the lowest task order 
	_getDraftInPreviousTaskOrder: function(parent_id, taskOrder){
		var draftTaskInPreviousOrder;
		var gr_draftTasks = new GlideRecord('x_153465_discovert_route_task_instance');
		gr_draftTasks.addQuery("parent", parent_id);
		gr_draftTasks.addQuery("state", -6);
		gr_draftTasks.addQuery("task_order", "<", taskOrder);
		gr_draftTasks.orderBy("task_order");
		gr_draftTasks.query();
		if(gr_draftTasks.next()){
			draftTaskInPreviousOrder = gr_draftTasks.getUniqueValue();
		}
		return draftTaskInPreviousOrder;
	},

