		*/

	},

	// 2.5.3 - STRY0082087, STRY0083025, STRY0083027
	evaluateRestrictedGroupForForm: function(restrictedOUsandMembers){
		var formValues = restrictedOUsandMembers.returnFormValues;
		var formLabels = restrictedOUsandMembers.formLabels;

		var msgLineRet = formLabels.UI_Type == 'Portal' ? '<li>' : '\n';
		var msgLineEnd = formLabels.UI_Type == 'Portal' ? '</li>' : ' ';
		var msgLineBr = formLabels.UI_Type == 'Portal' ? '<br/>' : '\n';
		var msgLineBoldStart = formLabels.UI_Type == 'Portal' ? '<b>' : '';
		var msgLineBoldEnd = formLabels.UI_Type == 'Portal' ? '</b>' : '';

