	// 2.5.3 - STRY0082087, STRY0083025, STRY0083027
	getOUsForRestrictedGroupIdAbbrevName: function(restrictedGroup) {
		var ArrRestrictedOUIds = [];
		var ArrRestrictedOUAbbrevs = [];
		var ArrRestrictedOUNames = [];
		var OUsForRestrictedGroupIdAbbrevName = {};

		var ouMemArr = [];
		ouMemArr = new UserInfoScripts().getAllMembersSysIdsInGroup(restrictedGroup);
		var grOus = new GlideRecordSecure('x_153465_discovert_discover_office_hierarchy');
		var grMemberOus = new GlideRecordSecure('x_153465_discovert_discover_office_members');
		grMemberOus.addQuery('office_member', 'IN', ouMemArr.join(','));
		grMemberOus.query();
		while(grMemberOus.next()){
			ArrRestrictedOUIds.push(grMemberOus.getValue('discover_office_hierarchy'));
			if(grOus.get(grMemberOus.getValue('discover_office_hierarchy'))){
				ArrRestrictedOUAbbrevs.push(grOus.getValue('office_abbreviation'));
				ArrRestrictedOUNames.push(grOus.getValue('office_name'));
			}
		}
		// Get External OUs with contacts
		var grContactOus = new GlideRecordSecure('x_153465_discovert_organizational_contacts');
		grContactOus.addQuery('u_user_information', 'IN', ouMemArr.join(','));
		grContactOus.query();
		while(grContactOus.next()){
			if(grOus.get(grContactOus.getValue('u_contact_ou'))){
				// only add externals based on conatcts, do not add internal ous based on contacts
				if(grOus.u_external_flag==true){
					ArrRestrictedOUIds.push(grOus.getUniqueValue());
					ArrRestrictedOUAbbrevs.push(grOus.getValue('office_abbreviation'));
					ArrRestrictedOUNames.push(grOus.getValue('office_name'));
				}
			}
		}

		OUsForRestrictedGroupIdAbbrevName.OUIds = ArrRestrictedOUIds;
		OUsForRestrictedGroupIdAbbrevName.OUAbbrevs = ArrRestrictedOUAbbrevs;
		OUsForRestrictedGroupIdAbbrevName.OUNames = ArrRestrictedOUNames;

		return OUsForRestrictedGroupIdAbbrevName;
	},

	// 2.5.3 - STRY0082087, STRY0083025, STRY0083027
	// receives restricted group
	// returnes a memberArr restricted to people in the restricted group
	getMembersForRestrictedGroupIdNameEmailUserId: function(restricted_group) {
		var ArrRestrictedMemberIds = [];
		var ArrRestrictedMemberNames = [];
		var ArrRestrictedMemberEmails = [];
		var ArrRestrictedMemberUserIds = [];
		var MembersForRestrictedGroupIdNameEmailUserId = {};
		var grUser = new GlideRecordSecure('sys_user');
		var grGroup = new GlideRecordSecure('sys_user_group');
		var groupName = '';
		if(grGroup.get(restricted_group)){
			// note this should be the same for every user found since we are filtering based on group ID.
			groupName = grGroup.getDisplayValue();
		}
		// STRY0095102 - get the nest list of groups
		// NOTE: may want to look at loading this one time for performance.  
		// If loading, build an object with top group as the key 
		// and the list of all groups under the top group as a comman delimitted string.
		var UserPermissions = new UserInfoScripts();
		var restricted_group_s = UserPermissions.getRestrictedGroupsAndDescendents(restricted_group);
		var usersInGroup = new GlideRecordSecure('sys_user_grmember');
		// STRY0095102 - Use IN instead of equals to pull members from all parent groups
		usersInGroup.addQuery('group','IN', restricted_group_s);
		usersInGroup.query();
		while (usersInGroup.next()){
			ArrRestrictedMemberIds.push(usersInGroup.getValue('user'));
			if(grUser.get(usersInGroup.getValue('user'))){
				ArrRestrictedMemberNames.push(grUser.getValue('name'));
				ArrRestrictedMemberEmails.push(grUser.getValue('email'));
				ArrRestrictedMemberUserIds.push(grUser.getValue('user_name'));
			}
		}
		MembersForRestrictedGroupIdNameEmailUserId.groupName = groupName;
		MembersForRestrictedGroupIdNameEmailUserId.MemberIds = ArrRestrictedMemberIds;
		MembersForRestrictedGroupIdNameEmailUserId.MemberNames = ArrRestrictedMemberNames;
		MembersForRestrictedGroupIdNameEmailUserId.MemberEmails = ArrRestrictedMemberEmails;
		MembersForRestrictedGroupIdNameEmailUserId.MemberUserIds = ArrRestrictedMemberUserIds;
		return MembersForRestrictedGroupIdNameEmailUserId;
	},

