		if(formValues.poc_name && formValues.poc_name.id != '' 
			&& grUser.get(formValues.poc_name.id)) formValues.poc_name.name = grUser.getDisplayValue();
		if(formValues.u_internal_contact && formValues.u_internal_contact.id != '' 
			&& grUser.get(formValues.u_internal_contact.id)) formValues.u_internal_contact.name = grUser.getDisplayValue();
		if(formValues.u_subtask_assigned_member_s && formValues.u_subtask_assigned_member_s.ids != '') {
