		if(formValues.primary_assignee && formValues.primary_assignee.id != '' 
			&& grOrg.get(formValues.primary_assignee.id)) formValues.primary_assignee.abbr = grOrg.getValue('office_abbreviation');
		if(formValues.u_subtask_primary_assignee_s && formValues.u_subtask_primary_assignee_s.ids != '') {
			for(var j=0; j<formValues.u_subtask_primary_assignee_s.arrIds.length; j++){
				if(grOrg.get(formValues.u_subtask_primary_assignee_s.arrIds[j])) 
					formValues.u_subtask_primary_assignee_s.arrAbbrs.push(grOrg.getValue('office_abbreviation'));
			}
		}
		if(formValues.u_external_ou && formValues.u_external_ou.id != '' 
			&& grOrg.get(formValues.u_external_ou.id)) formValues.u_external_ou.abbr = grOrg.getValue('office_abbreviation');

		return formValues;
	},

		//---------------------------------------------------------------------------------------------
		// 2.5.13: 08.12.20 | KT | SEQ | STRY0076601: SEQ - Task Details page – Displays Task Tree View Indicators
		// STRY0122215 - changed current for parent id
		//---------------------------------------------------------------------------------------------
		setCountActiveSubTasks: function(parent_id){

			// RJ -Tasker 2.5 P2 - Certification
			var grTask = new GlideRecord('x_153465_discovert_route_task_instance');
			if(grTask.get(parent_id)){
				// find new child count - this is AFTER insert / delete
				var countSubtasks = new GlideAggregate('x_153465_discovert_route_task_instance');
				countSubtasks.addQuery('parent',parent_id);
				// STRY0122878 - added draft to the list of states not to count when counting active 
				countSubtasks.addQuery('state', "NOT IN", "3,4,7, -6");
				countSubtasks.addAggregate('COUNT');
				countSubtasks.query();
				var numberActiveSubtasks = 0;
				if(countSubtasks.next())
					numberActiveSubtasks = countSubtasks.getAggregate('COUNT');
				grTask.u_active_subtasks = numberActiveSubtasks;
				grTask.update('Tasker: Total number of active subtasks updated' + numberActiveSubtasks);
			}
		},

