		//---------------------------------------------------------------------------------------------
		// v2.7 // STRY0105125 STRY0105845
		//---------------------------------------------------------------------------------------------
		_getParentState: function(hasParent, parentId){
			var parentState = '';
			if(hasParent){
				var grParent = new GlideRecord('x_153465_discovert_route_task_instance');
				if(grParent.get(parentId)){
					parentState = grParent.state;
				}
			}

			return parentState;
		},

		//---------------------------------------------------------------------------------------------
		// v2.5.13 | 07.20.2020 | STRY0076605:  Sequential Review
		//---------------------------------------------------------------------------------------------
		getInitialState: function(current) {
			var answer = '';
			// STRY0105125 STRY0105845
			var parentId = current.parent + '';
			var hasParent = (parentId != '');
			var parentState = parseInt(this._getParentState(hasParent, parentId));

			if(current.state == -6 || (hasParent && parentState == -6)){
				answer = -6;
				return answer;
			}
			// STRY0076605 - check to see if task is in wait state due to task order
			if(!this.isTaskOrderOfTaskActive(current)){
				answer = -3;
			} else{
				if (current.u_wait_for_subtasks_to_finish == true) {
					answer = -3;
				} else {
					if (current.assigned_to.nil()) {
						answer = -5;
					}
					if (!current.assigned_to.nil()) {
						answer = 1;
					}
				}
			}
			return answer;
		},

		//---------------------------------------------------------------------------------------------
		// v2.5.13 | 08.08.2020 | STRY0076605:  Sequential Review
		//---------------------------------------------------------------------------------------------
		// DFCT0011050 - state of a task was being changed back from closed while deleting draft tasks 
		//               The delete of the draft task triggered a recount of tasks to check to see if the parent should come out of wait state
		//               The getUpdatedState function is called when reopening tasks to set the state of the task being reopened.
		//               As a result, a check of the active state in this function is being used to determine if reopen is being called combined with the task state.
		//               Since reopen sets the active to true before checking what state the task should be on reopen, we use active and the 3 closed states to determine if the task state should be set to an open state.
		//               A closed task will have a state and active both reflecting it and we should not reset a task in that state
		//               Also, current can cause conflicts with the global current object.  So, the function was updated to use grTask
		getUpdatedState: function(grTask) {
			// STRY0084582 
			var currentState = grTask.state;
			var draft = -6;
			var waiting = -3;
			var unassigned = -5;
			var	assigned = 1;
			var	accepted = 10;
			var	workInProgress = 13;
			var	inReview = 14;
			var	reWork = 15;
			var completed = 3;
			var completedIncomplete = 4;
			var cancelled = 7;
			var answer = '';
			var stillWaiting = false;
			var isActive = (grTask.active == true);

			// STRY0105125 STRY0105845
			var parentId = grTask.parent + '';
			var hasParent = (parentId != '');
			var parentState = this._getParentState(hasParent, parentId);
			// STRY0122589 - it should not matter what the parent is.  
			// If this task is in draft, it doesn't come out until the state is changed by publish
			// WASJ - if(currentState == draft && (!hasParent || parentState == draft)){
			if(currentState == draft){
				answer = draft;
				return answer;
			}

			// DFCT0011050
			if(!isActive && (currentState == completed || currentState == completedIncomplete || currentState == cancelled)){
				answer = currentState;
				return answer;
			}

			// STRY0076605 - check to see if task is in wait state due to task order
			if(!this.isTaskOrderOfTaskActive(grTask)){
				answer = -3;
			} else{
				// STRY0122878 - need to check if there are draft tasks
				//               if there are draft tasks, then they are only counted if there are no completed tasks
				if (grTask.u_wait_for_subtasks_to_finish == true) {
					// count completed task
					var closedCount = this.countClosed(grTask.getUniqueValue());
					// count draft tasks
					var draftCount = this.countDraft(grTask.getUniqueValue());
					// count draft tasks
					var activeCount = this.countActive(grTask.getUniqueValue());
					// all subtasks are closed, come out of waiting state
					if(grTask.calchaschildren == 0){
						stillWaiting = true;
					} else if(closedCount == grTask.calchaschildren){
						stillWaiting = false;
					} else if(closedCount == 0 && (activeCount == draftCount)){
						stillWaiting = true;
					} else if(closedCount > 0 && (activeCount == draftCount)){
						stillWaiting = false;
					} else {
						stillWaiting = true;
					}
				}
				if(stillWaiting){
					answer = waiting;
				} else {
					// STRY0084582 
					if (grTask.assigned_to.nil()) {
						answer = unassigned;
					} else if (!grTask.assigned_to.nil() 
						&& currentState != assigned
						&& currentState != accepted
						&& currentState != workInProgress
						&& currentState != inReview
						&& currentState != reWork) {
						// do not update the state to assigned if the state is beyond assigned
						answer = assigned;
					} else {
						answer = currentState;
					}
				}
			}
			return answer;
		},

		//---------------------------------------------------------------------------------------------
		// v2.5.13 | 08.08.2020 | STRY0076617:  Order
		//---------------------------------------------------------------------------------------------
		isTaskOrderOfTaskActive: function(grTask){
			if(grTask.parent.nil()){
				// you have reached the top true should go all the way back down to say this task is active
				return true;
			}
			var grSubTasksActiveOrder = new GlideRecord('x_153465_discovert_route_task_instance');
			grSubTasksActiveOrder.addQuery('parent', grTask.getValue('parent') );
			grSubTasksActiveOrder.addQuery('active', true);
			grSubTasksActiveOrder.orderBy('task_order');
			grSubTasksActiveOrder.query();
			// some subtasks are still active
			if(grSubTasksActiveOrder.next()){
				if(parseInt(grSubTasksActiveOrder.task_order) < parseInt(grTask.task_order)){
					return false;  // at this level the order active is less than the order active of the task - return false
					// DFCT0010884 - moved recursive block so it executes if this is the first subtask at this level
				/*} else {
					// this level of the tree is active for this task
					var grTaskParent = new GlideRecord('x_153465_discovert_route_task_instance');
					if(grTaskParent.get(grTask.parent)){
						// if this is not the top level, go up again and determine if that level is active
						return this.isTaskOrderOfTaskActive(grTaskParent);
					} */
				}
			// DFCT0010884 - returning true here didn't account for adding a new task at the lowest level and the parent task paused by order by
			//} else {
			//	// no active tasks at this level, so, this task can be active at this level if the parent is active
			//	return true;
			}
			// DFCT0010884 - moved recursive block so it executes if this is the first subtask at this level
			// this level of the tree is active for this task
			var grTaskParent = new GlideRecord('x_153465_discovert_route_task_instance');
			if(grTaskParent.get(grTask.parent)){
				// if this is not the top level, go up again and determine if that level is active
				return this.isTaskOrderOfTaskActive(grTaskParent);
			} else {
				return true;
			}
		},

		//---------------------------------------------------------------------------------------------
		// v2.7.3 | 2022.05.05 | DFCT0010884 - All child/descendant tasks of an ORDERED TASK should be 
		//                                     in "WAIT" state until the earlier order task has been completed
		//---------------------------------------------------------------------------------------------
		pauseOrder: function (grTask){
			var grSubTasks = new GlideRecord('x_153465_discovert_route_task_instance');
			// Query to see if tasks are still active in this task order
			grSubTasks.addQuery('parent', grTask.getUniqueValue());
			grSubTasks.addQuery('active', true);
			grSubTasks.query();
			while(grSubTasks.next()){
				grSubTasks.state = -3;
				grSubTasks.update();
				// if this task is paused by order by, pause all children of the task
				if(grSubTasks.calchaschildren >0){
					this.pauseOrder(grSubTasks);
				}
			}
		},

		//---------------------------------------------------------------------------------------------
		// v2.5.13 | 08.13.2020 | // STRY0076618 - on close or cancel if an order is complete, start next order
		//---------------------------------------------------------------------------------------------
		onCloseCheckIfNewOrderStarts: function(grTask){
			if(grTask.parent.nil()){
				// you have reached the top true should go all the way back down to say this task is active
				return;
			}
			var grSubTasksActiveOrder = new GlideRecord('x_153465_discovert_route_task_instance');
			// Query to see if tasks are still active in this task order
			grSubTasksActiveOrder.addQuery('parent', grTask.getValue('parent') );
			grSubTasksActiveOrder.addQuery('active', true);
			grSubTasksActiveOrder.addQuery('task_order', grTask.task_order);
			grSubTasksActiveOrder.query();
			if(grSubTasksActiveOrder.next()){
				// no work to do, exit close routine
				return;
			}
			// get the parent of this task
			var grParent = new GlideRecord('x_153465_discovert_route_task_instance');
			if(grParent.get(grTask.getValue('parent'))){
				this.startOrder(grParent);
			}

		},

		startOrder: function(grTask){
			var grSubTasksActiveOrder = new GlideRecord('x_153465_discovert_route_task_instance');
			// if we are here, start the next order
			grSubTasksActiveOrder.addQuery('parent', grTask.getUniqueValue());
			grSubTasksActiveOrder.addQuery('active', true);
			grSubTasksActiveOrder.orderBy('task_order');
			grSubTasksActiveOrder.query();
			var activeOrder = 0;
			// some subtasks are still active
			while(grSubTasksActiveOrder.next()){
				// set the active order to the value of the first active order found
				if(activeOrder==0)
					activeOrder = grSubTasksActiveOrder.task_order;

				// the first task that is not in the first order, break out of while
				if(parseInt(activeOrder) != parseInt(grSubTasksActiveOrder.task_order))
					break;
				grSubTasksActiveOrder.state = this.getUpdatedState(grSubTasksActiveOrder);
				grSubTasksActiveOrder.update();
				if(grSubTasksActiveOrder.calchaschildren > 0){
					// this task is being started due to order, start any non-dependdent child tasks
					this.startOrder(grSubTasksActiveOrder);
				}
			}
		},

		//---------------------------------------------------------------------------------------------
		// KT - TLV - STRY0057360 - Macro Widget: 06.02.20
		//---------------------------------------------------------------------------------------------
		getAncestors: function(taskSysID, pad) {
			var answer = '';

			var grTask = new GlideRecord('x_153465_discovert_route_task_instance');
			if(grTask.get(taskSysID)){
				if (!grTask.parent.nil()) {
					answer += pad + grTask.sys_id + ',';
					answer += this.getAncestors(grTask.parent, answer);
				} else answer += pad + taskSysID + ',';
			}
			return answer;
		},

		getTaskRecordAncestors: function(gr_task){
			// if we are at the top record, return the id of this record
			if (gr_task.parent.nil()) {
				// top record is just retured
				return gr_task.getUniqueValue();
			} else {
				// if not at the top, get the next parent
				var gr_parent = new GlideRecord('x_153465_discovert_route_task_instance');
				if(gr_parent.get(gr_task.parent)){
					// put ancestor records before parent record, top record will be added when we hit the top record
					return this.getTaskRecordAncestors(gr_parent) + "," + gr_parent.getUniqueValue();
				}
			}
		},

		getSubTaskProgress: function(parentId) {
			var stateSubTaskProgress = -5;
			var grSubTasks = new GlideRecord('x_153465_discovert_route_task_instance');
			grSubTasks.addQuery('parent', parentId);
			grSubTasks.orderBy('state_order');
			grSubTasks.query();

			if (grSubTasks.next())
				stateSubTaskProgress = grSubTasks.state;

			return stateSubTaskProgress;
		},

		countClosed: function(parentId) {
			var countClosed = 0;
			var gaCountChildrenClosed = new GlideAggregate('x_153465_discovert_route_task_instance');
			//Query child tables for all records with current parent.
			gaCountChildrenClosed.addAggregate('COUNT');
			gaCountChildrenClosed.addQuery('parent', parentId);
			// Count all closed states
			// "Closed Complete" - 3
			// "Closed Incomplete" - 4
			// "Cancelled" - 7
			gaCountChildrenClosed.addQuery('state', "IN", "3,4,7");

			gaCountChildrenClosed.query();

			if (gaCountChildrenClosed.next())
				countClosed += gaCountChildrenClosed.getAggregate('COUNT');

			return countClosed;
		},

		// STRY0122878 
		countDraft: function(parentId) {
			var countDraft = 0;
			var gaCountChildrenDraft = new GlideAggregate('x_153465_discovert_route_task_instance');
			//Query child tables for all records with current parent.
			gaCountChildrenDraft.addAggregate('COUNT');
			gaCountChildrenDraft.addQuery('parent', parentId);
			// Count draft state
			// "Draft" - -6
			gaCountChildrenDraft.addQuery('state', "IN", "-6");

			gaCountChildrenDraft.query();

			if (gaCountChildrenDraft.next())
				countDraft += gaCountChildrenDraft.getAggregate('COUNT');

			return countDraft;
		},

		// STRY0122878 
		countActive: function(parentId) {
			var countActive = 0;
			var gaCountChildrenActive = new GlideAggregate('x_153465_discovert_route_task_instance');
			//Query child tables for all records with current parent.
			gaCountChildrenActive.addAggregate('COUNT');
			gaCountChildrenActive.addQuery('parent', parentId);
			gaCountChildrenActive.addQuery('active', true);
			gaCountChildrenActive.query();

			if (gaCountChildrenActive.next())
				countActive += gaCountChildrenActive.getAggregate('COUNT');

			return countActive;
		},

		calculateChildren: function (gr_parent){
			// find new child count - this is AFTER insert / delete
			var countChildren =new GlideAggregate('x_153465_discovert_route_task_instance');
			countChildren.addQuery('parent',gr_parent.getUniqueValue());
			countChildren.addAggregate('COUNT');
			countChildren.query();
			var numChildren = 0;
			if(countChildren.next()) 
				numChildren = countChildren.getAggregate('COUNT');
			return numChildren;
		},

		// RAJ - found this while working another story and noticed this would not work.
		//       this function doesn't appear to be used as where it was called (in an ACL) it is commented out
		//       but fixed any way in case used later
		hasActiveTaskInOu: function(userId, ouId) {
			var activeTasksInOU = false;
			//lookup Task for assigned user in subject ou with active flag
			var records = new GlideAggregate("x_153465_discovert_route_task_instance");
			records.addQuery("assigned_to", userId);
			records.addQuery("primary_assignee", ouId);
			records.addQuery("active", true);
			records.addAggregate("COUNT");
			records.query();
			if(records.next()){
				activeTasksInOU = records.getAggregate("COUNT") > 0;
			}
			return activeTasksInOU;
		},

		type: 'TaskerHelpers'
	};
